//! Tests for synthesized before/after DOCX pairs that exercise the full
//! diff -> redline -> export pipeline.
//!
//! Fixture documents are generated by `testdata/synthesized/create_docs.py`.
//!
//! Tests encode **desired behavior**: what the redline DOCX *should* contain.
//! Tests that assert correct behavior the system can't yet produce are
//! marked `#[ignore]` with the gap reason — they become a live TODO list.

use std::fs;

use stemma::{
    DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta, redline_extract::extract_redline,
};

const TESTDATA: &str = "testdata/synthesized";

// ── helpers ──────────────────────────────────────────────────────────────

fn redline_meta() -> TransactionMeta {
    TransactionMeta {
        author: "synthesized_redline".to_string(),
        reason: Some("synthesized redline test".to_string()),
        timestamp_utc: Some("2025-06-01T00:00:00Z".to_string()),
    }
}

/// Run the full redline pipeline on a before/after pair and return the
/// exported DOCX bytes.
///
/// Steps:
/// 1. Import both documents
/// 2. diff_and_redline
/// 3. Export with ExportMode::Redline
/// 4. Re-import exported bytes (export contract)
fn run_redline_pipeline(before_path: &str, after_path: &str) -> Vec<u8> {
    let before_bytes =
        fs::read(before_path).unwrap_or_else(|err| panic!("read {before_path}: {err}"));
    let after_bytes = fs::read(after_path).unwrap_or_else(|err| panic!("read {after_path}: {err}"));

    let runtime = SimpleRuntime::new();

    let import_before = runtime
        .import_docx(&before_bytes)
        .unwrap_or_else(|err| panic!("import {before_path}: {err:?}"));
    let import_after = runtime
        .import_docx(&after_bytes)
        .unwrap_or_else(|err| panic!("import {after_path}: {err:?}"));

    let apply = runtime
        .diff_and_redline(
            &import_before.doc_handle,
            &import_after.doc_handle,
            redline_meta(),
        )
        .unwrap_or_else(|err| panic!("diff_and_redline failed: {err:?}"));
    assert!(apply.applied, "redline must be marked as applied");

    let exported = runtime
        .export_docx(&import_before.doc_handle, ExportMode::Redline)
        .unwrap_or_else(|err| panic!("export_docx failed: {err:?}"));
    assert!(!exported.is_empty(), "exported DOCX must not be empty");

    // Export contract: re-import must succeed.
    let verify = SimpleRuntime::new();
    verify
        .import_docx(&exported)
        .unwrap_or_else(|err| panic!("re-import of exported redline DOCX failed: {err:?}"));

    exported
}

// ── text substitution ────────────────────────────────────────────────────

/// "brown" → "red", "jumps" → "leaps" within a paragraph.
/// ReplaceText with tracked changes must produce <w:del> / <w:ins>.
#[test]
fn synthesized_text_substitution() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/text-substitution/before.docx"),
        &format!("{TESTDATA}/text-substitution/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_del = extract.all_deleted_text().join(" | ");
    let all_ins = extract.all_inserted_text().join(" | ");

    assert!(
        all_del.contains("brown"),
        "deleted text should contain 'brown', got: {all_del}"
    );
    assert!(
        all_ins.contains("red"),
        "inserted text should contain 'red', got: {all_ins}"
    );
    assert!(
        all_del.contains("jumps"),
        "deleted text should contain 'jumps', got: {all_del}"
    );
    assert!(
        all_ins.contains("leaps"),
        "inserted text should contain 'leaps', got: {all_ins}"
    );
}

// ── paragraph insertion ──────────────────────────────────────────────────

/// An inserted paragraph should appear inside <w:ins> tracked-change
/// markup so Word displays it as an insertion.
#[test]
fn synthesized_paragraph_insertion_has_tracked_markup() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/paragraph-insertion/before.docx"),
        &format!("{TESTDATA}/paragraph-insertion/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_ins = extract.all_inserted_text().join(" | ");

    assert!(
        all_ins.contains("freshly inserted"),
        "inserted paragraph should appear inside <w:ins>, got: {all_ins}"
    );
}

// ── paragraph deletion ───────────────────────────────────────────────────

/// "This paragraph will be deleted." must appear inside <w:del>.
/// Surviving paragraphs must be present unchanged.
#[test]
fn synthesized_paragraph_deletion() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/paragraph-deletion/before.docx"),
        &format!("{TESTDATA}/paragraph-deletion/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_del = extract.all_deleted_text().join(" | ");

    assert!(
        all_del.contains("will be deleted"),
        "deleted text should contain 'will be deleted', got: {all_del}"
    );

    // Surviving paragraphs must appear in accept-all text
    let accepted: String = extract
        .body
        .iter()
        .map(|p| p.accept_text())
        .collect::<Vec<_>>()
        .join("\n");
    assert!(
        accepted.contains("Keep this paragraph"),
        "'Keep this paragraph' missing from accept-all text"
    );
    assert!(
        accepted.contains("Keep this one too"),
        "'Keep this one too' missing from accept-all text"
    );
}

// ── mixed paragraph changes ──────────────────────────────────────────────

/// Modify + insert + delete in one document.
/// Substitutions and deletions must produce correct tracked changes.
#[test]
fn synthesized_mixed_paragraph_changes() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/mixed-paragraph-changes/before.docx"),
        &format!("{TESTDATA}/mixed-paragraph-changes/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_del = extract.all_deleted_text().join(" | ");
    let all_ins = extract.all_inserted_text().join(" | ");

    // "original" → "modified" substitution
    assert!(
        all_del.contains("original"),
        "deleted text should contain 'original', got: {all_del}"
    );
    assert!(
        all_ins.contains("modified"),
        "inserted text should contain 'modified', got: {all_ins}"
    );

    // "Beta paragraph to be removed." deletion
    assert!(
        all_del.contains("Beta") || all_del.contains("removed"),
        "deleted text should contain Beta paragraph content, got: {all_del}"
    );

    // "old" → "new" substitution in Delta paragraph
    assert!(
        all_del.contains("old"),
        "deleted text should contain 'old', got: {all_del}"
    );
    assert!(
        all_ins.contains("new"),
        "inserted text should contain 'new', got: {all_ins}"
    );

    // Unchanged paragraph survives in accept-all text
    let accepted: String = extract
        .body
        .iter()
        .map(|p| p.accept_text())
        .collect::<Vec<_>>()
        .join("\n");
    assert!(
        accepted.contains("Gamma paragraph unchanged"),
        "unchanged 'Gamma' paragraph missing from accept-all text"
    );
}

