// ── table row addition ───────────────────────────────────────────────────

/// Adding a row to a table should produce tracked-change markup on the
/// new row (e.g. <w:trPr><w:ins .../></w:trPr>).
#[test]
fn synthesized_table_row_addition() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/table-row-addition/before.docx"),
        &format!("{TESTDATA}/table-row-addition/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_ins = extract.all_inserted_text().join(" | ");

    assert!(
        all_ins.contains("A3") || all_ins.contains("B3"),
        "inserted row content should appear inside tracked changes, got: {all_ins}"
    );
}

// ── table row deletion ───────────────────────────────────────────────────

/// Deleting a row from a table should produce tracked-change markup:
/// `<w:trPr><w:del .../></w:trPr>` plus `<w:del>` wrappers on cell content.
/// The deleted row's text should appear as Deleted spans in the extraction.
#[test]
fn synthesized_table_row_deletion() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/table-row-deletion/before.docx"),
        &format!("{TESTDATA}/table-row-deletion/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");
    let all_del = extract.all_deleted_text().join(" | ");

    // The middle row (A2, B2) was deleted.
    assert!(
        all_del.contains("A2") || all_del.contains("B2"),
        "deleted row content should appear inside tracked changes, got: {all_del}"
    );

    // Accept-all text should NOT contain the deleted row content.
    let accepted: String = extract
        .body
        .iter()
        .map(|p| p.accept_text())
        .collect::<Vec<_>>()
        .join("\n");
    assert!(
        !accepted.contains("A2"),
        "accept-all text should not contain deleted row content 'A2', got: {accepted}"
    );

    // Reject-all text should contain the deleted row content.
    let rejected: String = extract
        .body
        .iter()
        .map(|p| p.reject_text())
        .collect::<Vec<_>>()
        .join("\n");
    assert!(
        rejected.contains("A2"),
        "reject-all text should contain deleted row content 'A2', got: {rejected}"
    );
}

// ── header modification ──────────────────────────────────────────────────

/// "Original Header" → "Modified Header" should produce tracked changes
/// in the header XML part.
#[test]
fn synthesized_header_modification() {
    let exported = run_redline_pipeline(
        &format!("{TESTDATA}/header-modification/before.docx"),
        &format!("{TESTDATA}/header-modification/after.docx"),
    );

    let extract = extract_redline(&exported).expect("extract_redline");

    // Find a header part in the stories map.
    let (deleted, inserted) = ["word/header1.xml", "word/header2.xml", "word/header3.xml"]
        .iter()
        .find_map(|part| extract.tracked_changes_in(part))
        .expect("exported DOCX should contain at least one header part with changes");

    let all_del = deleted.join(" | ");
    let all_ins = inserted.join(" | ");

    assert!(
        all_del.contains("Original"),
        "header should have tracked deletion of 'Original', got: {all_del}"
    );
    assert!(
        all_ins.contains("Modified"),
        "header should have tracked insertion of 'Modified', got: {all_ins}"
    );
}

